import json

items = _input.all()
results = []
for item in items:
    ai_response = item.json.get('message', {}).get('content', item.json.get('text', '{}'))
    try:
        score_data = json.loads(ai_response)
    except:
        score_data = {'score': 0, 'tier': 'cold', 'reasoning': 'parse_error', 'recommended_action': 'retry'}

    results.append({
        'json': {
            'lead_id': f"LEAD-{item.json.get('rotation_id', '000')}",
            'company': item.json.get('company', ''),
            'contact_email': item.json.get('contact_email', ''),
            'score': score_data.get('score', 0),
            'tier': score_data.get('tier', 'cold'),
            'reasoning': score_data.get('reasoning', ''),
            'recommended_action': score_data.get('recommended_action', ''),
            'proxy_host': item.json.get('proxy_host', ''),
            'qualified_at': '{{ $now.toISO() }}'
        }
    })
return results
